INSERT INTO "public"."news" ("id", "title", "excerpt", "category_id", "image_url", "source", "reporter", "content", "is_headline", "published_at", "created_at") VALUES ('0c5fec08-454b-4c4f-b5ae-9e73ecf0ec4f', 'Boğazlıyan Şekerspor Transfer Dönemine Hızlı Girdi', 'Yeni sezon öncesi 3 önemli oyuncu ile anlaşma sağlandı. Hedef şampiyonluk.', 'spor', 'https://blogger.googleusercontent.com/img/a/AVvXsEg9MurpvFaJLmO7VYR0ygz5YyGOHQig_GJZUcMzsSt4d_onWD02ByHtL3ci45HY3Cx2GAb_U12hqxvi6iRebZq95VEiqtwqRB1gcB_ilcYKpgBQ-1proVW1IoQtHEoN3UZQtx4kCFcqF00tZT_lERjAg9XrmQgejYfxZOcNqkOjf_4g1zBrPklP5Vb-d9Ob', 'Yerel Spor', 'Muhabir: deneme', '[{"text":"Boğazlıyan Belediyesi tarafından yapımı tamamlanan modern Kapalı Pazar Yeri, bugün düzenlenen görkemli bir törenle vatandaşların hizmetine sunuldu.","type":"lead"},{"text":"İlçe merkezinde uzun süredir ihtiyaç duyulan ve vatandaşların talepleri doğrultusunda projelendirilen tesis, hem esnafın hem de alışveriş yapan vatandaşların konforunu ön planda tutacak şekilde tasarlandı. Açılış törenine ilçe protokolü, esnaf odaları temsilcileri ve çok sayıda vatandaş katılım gösterdi.","type":"paragraph"},{"text":"Boğazlıyan''a yakışır, modern ve hijyenik bir pazar alanını ilçemize kazandırmanın mutluluğunu yaşıyoruz.","type":"quote"},{"text":"Belediye Başkanı yaptığı açılış konuşmasında, kışın soğuktan ve yağıştan, yazın ise sıcaktan etkilenmeden alışveriş yapılabilecek bu tesisin, bölge ekonomisine de canlılık katacağını ifade etti.","type":"paragraph"},{"text":"Modern İmkanlarla Donatıldı","type":"subheading"},{"text":"Yaklaşık 5000 metrekarelik bir alana kurulan yeni pazar yerinde, sadece satış alanları değil, aynı zamanda zabıta noktası, mescit, bebek bakım odası ve geniş kapasiteli otopark gibi sosyal donatılar da bulunuyor. Tesisin çatısında kullanılan özel sistem sayesinde gün ışığından maksimum seviyede faydalanılması sağlanarak enerji tasarrufu hedefleniyor.","type":"paragraph"},{"text":"Pazar esnafı da yeni yerlerine geçmenin heyecanını yaşarken, vatandaşlar yapılan hizmetten duydukları memnuniyeti dile getirdiler.","type":"paragraph"}]', 'false', '2026-01-03 07:35:08.617095+00', '2026-01-03 11:35:08.617095+00'), ('104d6d23-2a58-4401-85d9-1712a042ca31', 'Yeni Kapalı Pazar Yeri Törenle Hizmete Açıldı', 'Yeni sezon öncesi 3 önemli oyuncu ile anlaşma sağlandı. Hedef şampiyonluk.', 'gundem', 'https://blogger.googleusercontent.com/img/a/AVvXsEg9MurpvFaJLmO7VYR0ygz5YyGOHQig_GJZUcMzsSt4d_onWD02ByHtL3ci45HY3Cx2GAb_U12hqxvi6iRebZq95VEiqtwqRB1gcB_ilcYKpgBQ-1proVW1IoQtHEoN3UZQtx4kCFcqF00tZT_lERjAg9XrmQgejYfxZOcNqkOjf_4g1zBrPklP5Vb-d9Ob', 'Yerel Spor', 'Muhabir: deneme', '[{"text":"Boğazlıyan Belediyesi tarafından yapımı tamamlanan modern Kapalı Pazar Yeri, bugün düzenlenen görkemli bir törenle vatandaşların hizmetine sunuldu.","type":"lead"},{"text":"İlçe merkezinde uzun süredir ihtiyaç duyulan ve vatandaşların talepleri doğrultusunda projelendirilen tesis, hem esnafın hem de alışveriş yapan vatandaşların konforunu ön planda tutacak şekilde tasarlandı. Açılış törenine ilçe protokolü, esnaf odaları temsilcileri ve çok sayıda vatandaş katılım gösterdi.","type":"paragraph"},{"text":"Boğazlıyan''a yakışır, modern ve hijyenik bir pazar alanını ilçemize kazandırmanın mutluluğunu yaşıyoruz.","type":"quote"},{"text":"Belediye Başkanı yaptığı açılış konuşmasında, kışın soğuktan ve yağıştan, yazın ise sıcaktan etkilenmeden alışveriş yapılabilecek bu tesisin, bölge ekonomisine de canlılık katacağını ifade etti.","type":"paragraph"},{"text":"Modern İmkanlarla Donatıldı","type":"subheading"},{"text":"Yaklaşık 5000 metrekarelik bir alana kurulan yeni pazar yerinde, sadece satış alanları değil, aynı zamanda zabıta noktası, mescit, bebek bakım odası ve geniş kapasiteli otopark gibi sosyal donatılar da bulunuyor. Tesisin çatısında kullanılan özel sistem sayesinde gün ışığından maksimum seviyede faydalanılması sağlanarak enerji tasarrufu hedefleniyor.","type":"paragraph"},{"text":"Pazar esnafı da yeni yerlerine geçmenin heyecanını